```class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        if (num2 == 0) return num1 == 0 ? 0 : -1;
        int cnt = 0;
        while (num1 != 0) {
            int i = num1 % 2 == 0 ? num1 / 2 : (num1 - 1) / 2;
            num1 -= 2 * i + num2;
            cnt++;
        }
        return cnt;
    }
};
